import { keys } from "@alanscodelog/utils";
const defaultKeyNamer = ({ i, name }) => `${name}-${i}`;
const padNum = (num, limit, steps) => {
  const n = num / steps * limit;
  const rounded = Math.floor(n);
  return rounded.toString().padEnd(limit.toString().length - 1, "0");
};
const paddedKeyNamer = (keyLimit = 1e3) => ({ totalSteps, i, name }) => {
  const start = `${name}-`;
  return `${start}${padNum(i, keyLimit, totalSteps)}`;
};
const paddedByStepKeyNamer = (stepPadAmount = 100) => ({ i, name }) => {
  const num = i * stepPadAmount;
  const roundedString = Math.floor(num);
  const start = `${name}-`;
  return `${start}${roundedString}`.padEnd(start.length + 3, "0");
};
const tailwindColorKeyNamer = ({ i, name, separator }) => `${name}${separator}${["50", "100", "200", "300", "400", "500", "600", "700", "800", "900", "950"][i]}`;
const createArrayfromRatio = ({ ratio, length }) => {
  const res = [...Array(length)].reduce((arr, _, i) => {
    arr.push(arr[i] * ratio);
    return arr;
  }, [1]);
  return res;
};
const roundIfNeeded = (roundTo, num) => {
  if (typeof num === "number") {
    if (roundTo !== false && roundTo > -1) {
      return +num.toFixed(roundTo);
    }
    return num;
  }
  return num;
};
const scaleValue = ({ start, steps, step }) => Array.isArray(steps) ? steps[step] * start : step * start;
const lerpValue = ({ start, end, percent }) => start + (end - start) * percent;
const createNumericalInterpolator = (interpolator = lerpValue) => (opts) => {
  const { start, end, exclude, roundTo } = opts;
  const val = {};
  for (const key of Object.keys(start.value)) {
    if (exclude.includes(key)) {
      val[key] = start.value[key];
      continue;
    }
    val[key] = start.value[key];
    const startValue = start.value[key];
    const endValue = end.value[key];
    if (typeof startValue === "number" && typeof endValue === "number") {
      const interpolated = interpolator({ ...opts, start: startValue, end: endValue });
      if (typeof interpolated === "number" && isNaN(interpolated)) {
        throw new Error(`Interpolation for key ${key} from ${startValue} to ${endValue} resulted in ${interpolated}.`);
      }
      val[key] = roundIfNeeded(roundTo, interpolated);
    }
  }
  return val;
};
const lerp = createNumericalInterpolator();
const modifiyKeys = (modify, obj) => {
  const res = {};
  for (const key of keys(obj)) {
    res[modify(key)] = obj[key];
  }
  return res;
};
const cssObjectToString = (obj) => Object.entries(obj).map(([key, value]) => `${key}: ${value};`).join("");
const escapeKey = (key, sep) => key.replace(/[^a-zA-Z0-9_-]/g, sep);
export {
  createArrayfromRatio,
  createNumericalInterpolator,
  cssObjectToString,
  defaultKeyNamer,
  escapeKey,
  lerp,
  lerpValue,
  modifiyKeys,
  padNum,
  paddedByStepKeyNamer,
  paddedKeyNamer,
  roundIfNeeded,
  scaleValue,
  tailwindColorKeyNamer
};
